const now = Date.now();
const cutoff = now - 24 * 60 * 60 * 1000;

const filtered = items.filter(item => {
  const dateStr = item.json.isoDate || item.json.pubDate || item.json.date || null;
  if (!dateStr) return false;
  const pubTime = new Date(dateStr).getTime();
  if (isNaN(pubTime)) return false;
  return pubTime >= cutoff;
});

if (filtered.length === 0) {
  return [{
    json: {
      _noArticles: true,
      message: "No articles found in the last 24 hours.",
      checkedAt: new Date().toISOString()
    }
  }];
}

console.log(`✅ ${filtered.length} articles passed the 24h filter (out of ${items.length} total)`);

return filtered;

// Access workflow static memory
const store = $getWorkflowStaticData('global');

// Initialize storage array if it doesn't exist
if (!store.collectedSummaries) {
  store.collectedSummaries = [];
}

// Push current loop item
store.collectedSummaries.push({
  professional_summary: $json.professional_summary,
  data: $json.data
});

// Return current item so the loop continues
return $input.item;

const store = $getWorkflowStaticData('global');

const results = store.collectedSummaries || [];

// Optional: clear memory for next run
store.collectedSummaries = [];

return [
  {
    json: {
      all_summaries: results
    }
  }
];

// Ensure we are working with the input items
return $input.all().map(item => {
  // Capture the output from your AI Agent
  let text = item.json.output || "";

  // 1. Convert literal '\n' strings into actual line breaks
  let formatted = text.replace(/\\n/g, '\n');

  // 2. Remove the ugly dashed separators (-------)
  formatted = formatted.replace(/-{3,}/g, '');

  // 3. Fix paragraph spacing (ensuring a clean gap)
  formatted = formatted.replace(/\n{3,}/g, '\n\n').trim();

  return {
    json: {
      professional_summary: formatted
    }
  };
});
